import{_ as e,o as i,c as s,a2 as a}from"./chunks/framework.DGp-bpT-.js";const k=JSON.parse('{"title":"Security Model","description":"","frontmatter":{},"headers":[],"relativePath":"guide/security.md","filePath":"guide/security.md"}'),n={name:"guide/security.md"};function r(o,t,l,d,h,p){return i(),s("div",null,[...t[0]||(t[0]=[a(`<h1 id="security-model" tabindex="-1">Security Model <a class="header-anchor" href="#security-model" aria-label="Permalink to &quot;Security Model&quot;">​</a></h1><p>DSO is designed with a security-first architecture. This page documents every security property and the rationale behind each design decision.</p><h2 id="core-guarantee-secrets-never-touch-disk" tabindex="-1">Core Guarantee: Secrets Never Touch Disk <a class="header-anchor" href="#core-guarantee-secrets-never-touch-disk" aria-label="Permalink to &quot;Core Guarantee: Secrets Never Touch Disk&quot;">​</a></h2><p>The most critical property of DSO&#39;s security model:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cloud Vault → DSO Agent (RAM) → Docker Unix Socket → Container (RAM)</span></span>
<span class="line"><span>                                                      ↑</span></span>
<span class="line"><span>                                           No disk write at any point</span></span></code></pre></div><p>Secret values exist only in:</p><ul><li>The agent&#39;s in-memory cache (RAM)</li><li>The container&#39;s environment (RAM)</li></ul><p>They are <strong>never</strong> written to:</p><ul><li>The filesystem in plaintext</li><li>Docker image layers</li><li>Docker&#39;s container configuration on disk</li></ul><h2 id="authentication-no-manual-credentials" tabindex="-1">Authentication: No Manual Credentials <a class="header-anchor" href="#authentication-no-manual-credentials" aria-label="Permalink to &quot;Authentication: No Manual Credentials&quot;">​</a></h2><p>DSO uses cloud-native machine identity, which means developers never handle production credentials directly.</p><table tabindex="0"><thead><tr><th>Provider</th><th>Production Auth Method</th><th>Configuration</th><th>Security Notes</th></tr></thead><tbody><tr><td>AWS</td><td>EC2 Instance Profile</td><td>Attach IAM role, DSO auto-detects</td><td>No static credentials</td></tr><tr><td>Azure</td><td>Managed Identity</td><td>Enable on VM/ACI</td><td>Auto-authenticates via IMDS</td></tr><tr><td>Vault</td><td>AppRole with wrapped secret</td><td>Use response wrapping</td><td>Secret ID never exposed</td></tr><tr><td>Local File</td><td>File permissions</td><td><code>0600</code>, owned by root</td><td>Never commit to git</td></tr></tbody></table><h2 id="unix-socket-transport" tabindex="-1">Unix Socket Transport <a class="header-anchor" href="#unix-socket-transport" aria-label="Permalink to &quot;Unix Socket Transport&quot;">​</a></h2><p>The CLI and agent communicate over a <strong>Unix domain socket</strong> (<code>/var/run/dso.sock</code> or similar), not a TCP port. This means:</p><ul><li>The secret transport channel is <strong>local to the host</strong> — no network exposure</li><li>Only processes running as root or in the <code>docker</code> group can access it</li><li>No TLS configuration required (operating system enforces permissions)</li></ul><h2 id="not-visible-in-docker-inspect" tabindex="-1">Not Visible in <code>docker inspect</code> <a class="header-anchor" href="#not-visible-in-docker-inspect" aria-label="Permalink to &quot;Not Visible in \`docker inspect\`&quot;">​</a></h2><p>When secrets are injected via <code>inject: env</code>, they are passed to <code>docker compose</code> via a temporary environment file that is deleted immediately after the stack starts.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Secrets are NOT visible in docker inspect</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> inspect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-container</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DB_PASSWORD</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → (no output)</span></span></code></pre></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The container does have the secret in its runtime environment (accessible via <code>docker exec ... env</code>). This is by design — it matches the same access model as any environment variable.</p></div><h2 id="provider-isolation" tabindex="-1">Provider Isolation <a class="header-anchor" href="#provider-isolation" aria-label="Permalink to &quot;Provider Isolation&quot;">​</a></h2><p>Each provider (AWS, Azure, Vault) runs as a <strong>separate subprocess</strong> communicating via RPC. This provides:</p><ul><li><strong>Process isolation</strong> — a bug or crash in one provider doesn&#39;t affect others</li><li><strong>Least privilege</strong> — each provider subprocess only has the credentials it needs</li><li><strong>Containment</strong> — a compromised provider can&#39;t access secrets from other providers</li></ul><h2 id="secret-purge-on-shutdown" tabindex="-1">Secret Purge on Shutdown <a class="header-anchor" href="#secret-purge-on-shutdown" aria-label="Permalink to &quot;Secret Purge on Shutdown&quot;">​</a></h2><p>When <code>docker dso down</code> is called, the agent:</p><ol><li>Removes all containers</li><li><strong>Clears the in-memory secret cache</strong></li><li>Terminates provider RPC subprocesses</li></ol><p>After a clean shutdown, no secret data remains in memory or on disk.</p><h2 id="audit-trail" tabindex="-1">Audit Trail <a class="header-anchor" href="#audit-trail" aria-label="Permalink to &quot;Audit Trail&quot;">​</a></h2><p>Every secret fetch, rotation event, and strategy decision is logged via structured logging. These logs can be forwarded to your SIEM (Splunk, Datadog, etc.):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;time&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2024-01-15T10:23:45Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;level&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;INFO&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;msg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Secret fetched&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;provider&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;aws&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;secret&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;myapp/db&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;success&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;time&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2024-01-15T10:24:00Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;level&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;INFO&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;msg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Rotation triggered&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;secret&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;myapp/db&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;strategy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;rolling&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;container&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;api&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="threat-model" tabindex="-1">Threat Model <a class="header-anchor" href="#threat-model" aria-label="Permalink to &quot;Threat Model&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Threat</th><th>DSO&#39;s Mitigation</th></tr></thead><tbody><tr><td>Developer commits .env to GitHub</td><td>No .env files needed</td></tr><tr><td>Secrets visible on developer laptops</td><td>Never stored on disk</td></tr><tr><td>Credential rotation requires downtime</td><td>Automated rolling rotation</td></tr><tr><td>Compromised developer machine</td><td>Machine holds no credentials — IAM role is VM-scoped</td></tr><tr><td>Internal pod/container reads another&#39;s secrets</td><td>Each container receives only its mapped secrets</td></tr><tr><td>Network interception</td><td>Unix socket (local only), no network transport</td></tr></tbody></table><h2 id="compliance" tabindex="-1">Compliance <a class="header-anchor" href="#compliance" aria-label="Permalink to &quot;Compliance&quot;">​</a></h2><p>DSO&#39;s architecture directly supports:</p><ul><li><strong>SOC2 Type II</strong> — Centralized access control, audit logging, zero disk persistence</li><li><strong>ISO 27001</strong> — Credential management and access control controls</li><li><strong>PCI-DSS</strong> — Secrets never stored in source code or on developer endpoints</li></ul>`,34)])])}const u=e(n,[["render",r]]);export{k as __pageData,u as default};
